const raw = $input.first().json;
const event = raw.event || raw.body?.event || 'no-event';
const data = raw.data || raw.body?.data || {};
const msgText = data.message?.conversation || data.message?.extendedTextMessage?.text || '';
const t = msgText.toLowerCase().trim();
if (event !== 'messages.upsert') return [{ json: { reply: 'skip', phoneNumber: '14432576836@s.whatsapp.net', skip: true } }];
if (t.includes('bot reply:')) return [{ json: { reply: 'skip', phoneNumber: '14432576836@s.whatsapp.net', skip: true } }];
const agents = ['aidan','jordan','scout','iris','atlas','nova','sage','pulse','orchestra'];
if (!t || !agents.some(a => t.startsWith(a))) return [{ json: { reply: 'skip', phoneNumber: '14432576836@s.whatsapp.net', skip: true } }];
const from = data.key?.remoteJid || data.remoteJid || '14432576836@s.whatsapp.net';
let reply = '';
const http = require('http');
const fireWebhook = async (path, payload) => {
  const bodyStr = JSON.stringify(payload);
  const opts = { hostname: 'host.docker.internal', port: 5678, path, method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(bodyStr) } };
  await new Promise(r => { const req = http.request(opts, res => { res.on('data',()=>{}); res.on('end',r); }); req.on('error',r); req.write(bodyStr); req.end(); });
};
const sendChunked = async (text, number) => {
  const chunks = [];
  for (let i = 0; i < text.length; i += 3800) chunks.push(text.substring(i, i + 3800));
  for (const chunk of chunks) {
    const mb = JSON.stringify({ number, textMessage: { text: chunk } });
    const wo = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(mb) } };
    await new Promise(r => { const req = http.request(wo, res => { res.on('data',()=>{}); res.on('end',r); }); req.on('error',r); req.write(mb); req.end(); });
    if (chunks.length > 1) await new Promise(r => setTimeout(r, 1000));
  }
};
if (t.startsWith('orchestra')) {
  const query = t.replace(/^orchestra[,\s]*/i,'').trim() || 'Full platform status — compliance, BD targets, grants, MEIA readiness';
  await fireWebhook('/webhook/aidan-orchestra', { query, from });
  reply = `Bot reply: 🎼 ORCHESTRA INITIATED\nFiring: Atlas + Scout + Jordan + Iris\nQuery: ${query.substring(0,80)}\n\nConsolidated brief incoming ~90 seconds.`;
} else if (t.startsWith('aidan')) {
  const cmd = t.replace(/^aidan[,\s]*/i,'').trim();
  if (cmd === 'help' || cmd === '?') {
    reply = 'Bot reply: AIDAN v2 Commands\n\nAgents:\n• Atlas SBIR/MEIA/MONK/BVLOS/V1-V7/Kott prep\n• Scout [target]\n• Jordan grant / Jordan grant detail\n• Iris deadlines\n\nOrchestration:\n• Orchestra [query] — fires ALL agents\n\nBriefings:\n• Aidan summary — last consolidated brief\n• Aidan brief | Aidan status | Aidan help';
  } else if (cmd === 'summary') {
    const fs = require('fs');
    try {
      const orchDir = '/data/Aidan_Outputs/Orchestra/';
      const files = fs.readdirSync(orchDir).filter(f => f.startsWith('Brief_') && f.endsWith('.txt')).sort().reverse();
      if (files.length === 0) {
        reply = 'Bot reply: 📭 No consolidated brief found yet.\nFire Orchestra to generate one: say Orchestra';
      } else {
        const latestFile = files[0];
        const content = fs.readFileSync(orchDir + latestFile, 'utf8');
        const ts = latestFile.replace('Brief_','').replace('.txt','').replace(/T/,' ').substring(0,16);
        const header = `Bot reply: 📋 AIDAN SUMMARY (on-demand)\nBrief: ${ts} UTC\n\n`;
        const fullMsg = header + content;
        await sendChunked(fullMsg, from);
        return [{ json: { reply: 'skip', phoneNumber: from, skip: true } }];
      }
    } catch(e) {
      reply = 'Bot reply: ⚠️ Error reading summary: ' + e.message;
    }
  } else if (cmd.includes('brief') || cmd.includes('status') || cmd.includes('morning')) {
    reply = `Bot reply: ${new Date().toLocaleString('en-US',{timeZone:'America/New_York'})} EST\nAidan v2 online. Agents: Atlas ✅ Scout ✅ Jordan ✅ Iris ✅\nOrchestra ready. Say Orchestra to fire all agents.\nSay Aidan summary to retrieve last brief.`;
  } else {
    reply = `Bot reply: Aidan received: ${cmd}\nSay Aidan help for full command menu.`;
  }
} else if (t.startsWith('jordan')) {
  const cmd = t.replace(/^jordan[,\s]*/i,'').trim();
  if (cmd.includes('grant detail') || cmd.includes('grant report')) {
    const fs = require('fs');
    try {
      const files = fs.readdirSync('/data/Aidan_Outputs/Jordan/').filter(f=>f.startsWith('Grant_Report')).sort().reverse();
      if (files.length > 0) {
        const rpt = fs.readFileSync('/data/Aidan_Outputs/Jordan/' + files[0], 'utf8');
        reply = 'Bot reply: ' + rpt.substring(0,3500) + '\n_(full report in Aidan_Outputs/Jordan)_';
      } else reply = 'Bot reply: No grant reports found. Say Jordan grant to run analysis.';
    } catch(e) { reply = 'Bot reply: Error reading reports: ' + e.message; }
  } else {
    await fireWebhook('/webhook/grant-writer', { trigger: 'whatsapp', from });
    reply = 'Bot reply: Jordan Grant Writer running. Report ready ~45 seconds.';
  }
} else if (t.startsWith('scout')) {
  const cmd = t.replace(/^scout[,\s]*/i,'').trim() || 'Maryland drone infrastructure inspection contracts 2026';
  await fireWebhook('/webhook/scout-research', { query: cmd });
  reply = `Bot reply: Scout running BD research: ${cmd.substring(0,60)}\nReport ready ~60 seconds.`;
} else if (t.startsWith('iris')) {
  await fireWebhook('/webhook/iris-monitor', { trigger: 'whatsapp', from });
  reply = 'Bot reply: Iris compliance check running... ~15 seconds.';
} else if (t.startsWith('atlas')) {
  const cmd = t.replace(/^atlas[,\s]*/i,'').trim();
  const validCmds = ['sbir','meia','monk','bvlos','kott prep','status','v1','v2','v3','v4','v5','v6','v7'];
  const matched = validCmds.find(c => cmd.toLowerCase().startsWith(c));
  const atlasCmd = 'Atlas ' + (matched ? matched.toUpperCase() : cmd || 'status');
  const detail = matched ? cmd.replace(new RegExp(matched,'i'),'').trim() : cmd;
  await fireWebhook('/webhook/atlas-architect', { command: atlasCmd, detail: detail || '' });
  reply = `Bot reply: Atlas running: ${atlasCmd}\nReport ready ~45 seconds.`;
} else if (t.startsWith('nova') || t.startsWith('sage') || t.startsWith('pulse')) {
  const name = t.split(/\s/)[0];
  reply = `Bot reply: ${name.charAt(0).toUpperCase()+name.slice(1)} not yet built. Say Orchestra to fire all live agents, or Aidan help for menu.`;
} else {
  reply = 'Bot reply: Command not recognized. Say Aidan help for the full menu.';
}
return [{ json: { reply, phoneNumber: from, skip: false } }];

const input = $input.first().json;
if (input.skip || !input.reply || input.reply === 'skip') return [{ json: { success: true, skipped: true } }];
const number = (input.phoneNumber || '14432576836@s.whatsapp.net').includes('@lid') ? '14432576836@s.whatsapp.net' : (input.phoneNumber || '14432576836@s.whatsapp.net');
const body = JSON.stringify({ number, textMessage: { text: input.reply } });
const opts = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(body) } };
const result = await new Promise((resolve, reject) => {
  const http = require('http');
  const req = http.request(opts, res => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve({ status: res.statusCode })); });
  req.on('error', reject); req.write(body); req.end();
});
return [{ json: { success: true, result } }];
